tutorialsInfo_pt = {
-- Bï¿½sico --
    {
        {name = "01. Introduï¿½ï¿½o", text = "PokeMMO ï¿½ um servidor com uma base ï¿½nica e sistemas exclusivos.\n\nBuscamos trazer sempre inovaï¿½ï¿½o e diversï¿½o para todos nossos jogadores.", img = "imgs/basic/b1"}, 
        {name = "02. Controlar Objetos", text = "Para controlar itens, basta clicar e segurar o botï¿½o esquerdo do mouse pressionado e arrastï¿½-lo para onde quiser.", img = "imgs/basic/b2"}, 
        {name = "03. Interface", text = "Possuimos uma interface ï¿½nica e integrada para os jogadores, nela vocï¿½ tem acesso ï¿½ todos os comandos necessï¿½rios para sua jogatina.", img = "imgs/basic/b3"}, 
        {name = "04. Order", text = "Com o order, vocï¿½ pode controlar seu pokï¿½mon em batalha, escolhendo onde seu pokï¿½mon deve se posicionar.\n\nVocï¿½ pode usar o order clicando no ï¿½cone ou com o atalho 'BOTï¿½O DO MEIO DO MOUSE'.\n\nAlguns pokï¿½mons possuem habilidades que necessitam do uso do ORDER para serem ativadas, como Fly, Ride, Rock Smash, Cut, entre outras.\n\nVocï¿½ pode conferir mais sobre estas habilidades na aba 'habilidades'.", img = "imgs/basic/b4"},		       
        {name = "05. Pokï¿½dex", text = "Com a pokï¿½dex, vocï¿½ pode checar informaï¿½ï¿½es dos pokï¿½mons, como status, habilidades, evoluï¿½ï¿½es, moveset, etc...\n\nToda vez que vocï¿½ descobrir um pokï¿½mon novo vocï¿½ ganharï¿½ experiï¿½ncia por isso.\n\nVocï¿½ pode usar a pokï¿½dex clicando no ï¿½cone e depois clicando em um pokï¿½mon, ou usando o atalho 'CTRL+D' e em seguida clicar em um pokï¿½mon.", img = "imgs/basic/b5"}, 
        {name = "06. Mochila", text = "A mochila ï¿½ onde todos os seus itens, pokï¿½mons e espï¿½lios ficam armazenados.\n\nPara abrir a mochila, basta clicar no ï¿½cone ou usar o atalho 'CTRL+I'.", img = "imgs/basic/b6"},       
		{name = "07. Pesca", text = "Com a vara de pesca vocï¿½ pescar pokï¿½mons selvagens em qualquer fonte de ï¿½gua, sendo um ï¿½timo mï¿½todo de up.\n\nPara pescar, basta clicar no ï¿½cone e depois clicar em um corpo de ï¿½gua, ou utilizar o atalho 'CTRL+Z'.\n\nVocï¿½ pode alternar entre suas varas de pesca utilizando o atalho 'CTRL+X', porï¿½m, vocï¿½ precisa ter liberado as outras varas antes.", img = "imgs/basic/b7"},        
        {name = "08. Evoluï¿½ï¿½o", text = "O ï¿½cone de evoluï¿½ï¿½o permite que vocï¿½ evolua seus pokï¿½mons, desde que eles evoluam por level ou amor.\n\nPara evoluir um pokï¿½mon basta clicar no ï¿½cone e depois em seu pokï¿½mon que deseja evoluir, ou utilizar o atalho 'CTRL+E'.", img = "imgs/basic/b8"},
        {name = "09. Carteira", text = "A carteira mostra quanto dinheiro vocï¿½ tem salvo no banco e quantos tokens seu personagem tem.\n\nVocï¿½ pode conferir mais sobre os tokens na aba 'moedas'.", img = "imgs/basic/b9"},
        {name = "10. Caixa de Insï¿½gnia", text = "A caixa de insï¿½gnia serve para vocï¿½ checar quais insï¿½gnias seu personagem jï¿½ conquistou.\n\nCada insï¿½gnia aumenta o limite de diferenï¿½a de level em 5 nï¿½veis.\n\nVocï¿½ pode conferir mais sobre o sistema de nï¿½veis na aba 'sistemas'.", img = "imgs/basic/b10"},
        {name = "11. Pokï¿½BAR", text = "A pokï¿½bar ï¿½ uma interface para facilitar sua jogatina, vocï¿½ pode escolher rapidamente qual pokï¿½mon deseja soltar com apenas um clique. Basta clicar no ï¿½cone do pokï¿½mon desejado.\n\nVocï¿½ pode soltar seus pokï¿½mons com os atalhos 'CTRL+F1', 'CTRL+F2', 'CTRL+F3', 'CTRL+F4', 'CTRL+F5' e 'CTRL+F6', sendo a ordem dos ï¿½cones.", img = "imgs/basic/b11"},
		{name = "12. MoveBAR", text = "A movebar ï¿½ uma interface para facilitar sua jogatina, vocï¿½ pode escolher rapidamente qual ataque deseja usar com apenas um clique. Basta clicar no ï¿½cone do ataque desejado.\n\nVocï¿½ pode atacar utilizando as teclas de atalho 'F1', 'F2', 'F3', 'F4', 'F5', 'F6', 'F7', 'F8', 'F9', 'F10', 'F11' e 'F12', sendo a ordem dos ï¿½cones.", img = "imgs/basic/b12"},
		{name = "13. Minimapa", text = "O minimapa mostra sua localizaï¿½ï¿½o atual.\n\nVocï¿½ pode dar zoom-in e zoom-out utilizando a roleta do mouse.", img = "imgs/basic/b13"},  
        {name = "14. Conversando com NPC", text = "Vocï¿½ pode iniciar uma conversa com um NPC ao clicar em nele com o botï¿½o esquerdo do mouse.\n\nVocï¿½ pode fazer escolhas de diï¿½logo clicando em cima do texto azul, caso o NPC possua escolhas.", img = "imgs/basic/b14"},
    },
-- Sistemas Basicos--
    {
        {name = "01. Autoloot e Loot Comum", text = "O autoloot ï¿½ ativado automaticamente quando voce cria seu personagem. Todo o loot dropado pelos pokï¿½mons selvagens irï¿½o diretamente para seu inventario. Para desativar o autoloot basta digitar !autoloot.\n\nO loot comum ï¿½ o loot que todo pokï¿½mon de certa tipagem dropa, por exemplo, todo pokï¿½mon de ï¿½gua sempre vai ter a chance de dropar Water Gem, Water Pendant, etc...\nEsses loots nï¿½o aparecem na mensagem de loot, porï¿½m, sï¿½o pegos no autoloot.", img = "imgs/sistemabasic/sb1"},
        {name = "02. Captura", text = "Para capturar um pokï¿½mon, voce deve primeiro derrota-lo em combate.\nApï¿½s derrotado, vocï¿½ pode jogar uma pokï¿½ bola nele e tentar a captura.\nPara utilizar uma pokï¿½bola basta clicar com o botï¿½o direito nela e depois com o botï¿½o esquerdo no pokï¿½mon derrotado.\nSe a pokï¿½bola piscar verde no final, vocï¿½ capturou.\nSe a pokï¿½bola piscar vermelha no final, vocï¿½ nï¿½o capturou.\n\nEm nosso servidor possuimos diferentes tipos de pokï¿½ bolas.\nPokeball - Possui 1.0x de captura.\nGreatball - Possui 1.5x de captura.\nUltraball - Possui 2.0x de captura.\nMasterball - Sempre captura o pokï¿½mon.\nParkball - Possui 5.0x de captura, sï¿½ funciona no PokePARK.\nSaffariball - Possui 1.5x de captura, sï¿½ funciona no Saffari.\nHeavyball - Aumenta a chance de captura de acordo com o peso do pokï¿½mon derrotado.\nDuskball - Possui 3.5x de captura, sï¿½ funciona a noite.\nLoveball - Possui 4.0x de captura, sï¿½ funciona no mesmo pokï¿½mon que vocï¿½ estï¿½ utilizando.\nNetball - Possui 3.5x de captura, sï¿½ funciona em pokï¿½mons inseto e ï¿½gua.\nPremierball - Uma pokebola especial que possui 1.0x de captura, porï¿½m adiciona uma aura ao pokï¿½mon quando captura.\n\nAs pokï¿½bolas normais, como Pokeball, Greatball e Ultraball podem ser compradas no NPC Mark, no trading center.\nAs pokï¿½bolas especiais, como Heavyball, Duskball, Loveball, Netball e Premierball podem ser adquiridas com o NPC Token Collector no trading center.\nAs pokï¿½bolas Saffari e Parkball sï¿½o de uso exclusivo dos locais.\nA pokï¿½bola mais forte do jogo, Masterball, deve ser obtida por meio de quests e desafios.", img = "imgs/sistemabasic/sb2"},
        {name = "03. Level e EXP Share.", text = "Em nosso servidor, os pokï¿½mons possuem nï¿½vel e isso influencia diretamente o combate. Seu pokï¿½mon precisa de nï¿½vel para evoluir, usar ataques, etc...\nO pokï¿½mon que vocï¿½ utilizar para abatar o pokï¿½mon selvagem serï¿½ o que receberï¿½ experiï¿½ncia. Caso vocï¿½ esteja com um EXP Share em algum outro pokï¿½mon, ele tambï¿½m receberï¿½ experiï¿½ncia, mesmo nï¿½o participando do combate.\n\nEXP Share\nO exp share pode ser obtido no NPC Token Collector, no trading center. Para dar o exp share a um pokï¿½mon, basta clicar com o botao direito no exp share e o botao esquerdo no pokï¿½mon que deseja.", img = "imgs/sistemabasic/sb3"},
        {name = "04. Fly, ride e surf", text = "Se o seu pokï¿½mon possuir uma dessas habilidades, vocï¿½ poderï¿½ utiliza-las para ter uma melhor mobilidade.\n\nCom o Fly, basta utilizar o order em vocï¿½ mesmo com o pokï¿½mon solto, que ele irï¿½ atï¿½ vocï¿½ e iniciarï¿½ o fly. Utilize PageUp para subir um andar e PageDown para descer um andar. Para sair do fly basta dar order em vocï¿½ mesmo novamente.\n\nCom o ride, basta utilizar o order em vocï¿½ mesmo para montar e desmontar.\n\nCom o surf, basta andar em um corpo de ï¿½gua com o pokï¿½mon solto que vocï¿½ comeï¿½a a surfar.", img = "imgs/sistemabasic/sb4"},
    },		
-- Sistemas Avanï¿½ados --
    {
        {name = "01. TM System",      text = "O sistema de TM permite que vocï¿½ crie o pokï¿½mon perfeito pro seu estilo de jogo. Vocï¿½ utiliza o item 'clean disk' para ensinar TMs especificos para o seu pokï¿½mon. Para abrir a interface de TM basta segurar CTRL e clicar em cima do seu pokï¿½mon, em seguida clicar em 'TM System'.\n\nCada TM tem seu prï¿½prio custo, cooldown, nï¿½vel necessï¿½rio e pokï¿½mons que podem aprender, entï¿½o nem todos os pokï¿½mons podem aprender todos os TMs.", img = "imgs/sistemasadv/sa1"},
        {name = "02. EV System",     text = "O sistema de EV permite que voce balanceie melhor o seu pokï¿½mon, de acordo com sua necessidade. Cada pokï¿½mon pode receber atï¿½ 300 pontos de EV e pode colocar atï¿½ 150 pontos em cada status.\nO status HP aumenta a vida em 10 para cada ponto gasto, o status ATK aumenta o ataque em 1 para cada ponto gasto e o status DEF aumenta a defesa em 1 para cada ponto gasto. Para receber pontos basta abater os pokï¿½mons selvagens que vocï¿½ recebe EV Points.\n\nPara abrir a interface de EV basta segurar CTRL e clicar em cima do seu pokï¿½mon, em seguida clicar em 'EV System'.", img = "imgs/sistemasadv/sa2"},
        {name = "03. Dungeon System",         text = "Em nosso servidor, possuimos um sistema de Dungeon instanciado, onde vocï¿½ pode entrar e desafiar os pokï¿½mons lendï¿½rios.\nPara entrar na dungeon, basta acessar o dispositivo no ï¿½ltimo andar do centro pokï¿½mon.", img = "imgs/sistemasadv/sa3"},
        {name = "04. Tera System", 			text = "Pokï¿½mon Tera, Pokï¿½mon Terastal ou Tera System, ï¿½ quando um pokï¿½mon selvagem spawna com uma tipagem TERA. Pokï¿½mons com a tipagem TERA ignoram a tipagem natural do pokï¿½mon e possuem apenas a tipagem TERA.\nUm pokï¿½mon TERA de Fogo, aplicarï¿½ dano e receberï¿½ dano como se fosse do tipo Fogo originalmente. Adicionalmente, caso o pokï¿½mon utilize um ataque da mesma tipagem que seu TERA, ele causarï¿½ STAB equivalente a 2.0x, enquanto um pokï¿½mon sem TERA causarï¿½ 2.0x.\n\nPokï¿½mons TERA spawnam naturalmente pelo mundo e possuem uma aura ï¿½nica dada ï¿½ eles, o que os diferencia totalmente dos outros pokï¿½mons comuns. Pokï¿½mons teras sï¿½o extremamente raros e valiosos.", img = "imgs/sistemasadv/sa4"},
        {name = "05. Smeargle System",         text = "O Smeargle ï¿½ um pokï¿½mon ï¿½nico comparado ï¿½ todos os outros. Smeargle pode aprender ataques de outros pokï¿½mons, utilizando o seu ataque 'Sketch', cada smeargle possui 8 sketches que podem copiar 8 ataques diferentes.\n\nPara copiar um ataque de um pokï¿½mon, use o order no smeargle, para desbloquear ele. Depois, de target no pokemon que queira copiar e use o ataque da mesma numeraï¿½ï¿½o do ataque que voce quer copiar.\n\nExemplo: Se eu desejo copiar o ataque M4 de um pokï¿½mon, devo usar o Sketch 4.", img = "imgs/sistemasadv/sa5"},
        {name = "06. Ditto System",      text = "Ditto ï¿½ outro pokï¿½mon ï¿½nico, ele consegue copiar qualquer pokï¿½mon, desde que nï¿½o seja lendï¿½rio. Ditto copia os status, aparï¿½ncia e ataques do pokï¿½mon, sendo um ï¿½timo coringa no time. Capturar um Ditto nï¿½o ï¿½ uma tarefa muito fï¿½cil, ele se esconde pelo mundo se disfarï¿½ando de outros pokï¿½mons, entï¿½o vocï¿½ sï¿½ vai saber que ï¿½ um ditto quando derrotar o pokï¿½mon e uma gosma rosa aparecer no chï¿½o!\n\nPara copiar um pokï¿½mon com seu ditto, basta utilizar Order no pokï¿½mon que deseja copiar e para voltar ao normal, basta usar order no ditto.", img = "imgs/sistemasadv/sa6"},
        {name = "07. Computer System",         text = "Se voce adquirir um computador pessoal com o NPC Token Collector no trading center, vocï¿½ pode fazer uma variedade de coisas no seu computador (dentro de casa).\nPokï¿½ Food - Delivery de comida pra vocï¿½, as melhores comidas do mercado na palma da sua mï¿½o.\nRemove Held - Permite que vocï¿½ remova um held do seu pokï¿½mon, muito ï¿½til se vocï¿½ farma itens com 'Pickup' e 'PayDay'.\nRemove Exp Share - Permite remover o expshare de algum pokï¿½mon.\nRotom - Permite mudar a forma do Rotom.\nDeoxys - Permite mudar a forma do Deoxys.", img = "imgs/sistemasadv/sa7"},
        {name = "08. Held System",         text = "Helds aumentam status especï¿½ficos ou causam bonus em alguns efeitos. Helds podem ser adquiridos com o NPC Token Collector no trading center.\nOs helds possuem dois tiers, sendo um para pokï¿½mons de nï¿½vel 50- e outro para pokï¿½mons de nï¿½vel 50+.\n\nHeld Attack - aumenta o ataque do pokï¿½mon.\nHeld Defense - aumenta a defesa do pokï¿½mon.\nHeld Experience - aumenta a experiencia que o pokemon recebe.\nHeld Burn - aumenta o dano do status burn causado pelo pokï¿½mon.\nHeld Poison - aumenta o dano do status poison causado pelo pokï¿½mon.\nHeld Vitality - aumenta a vida do pokï¿½mon.\nHeld Wing - aumenta a velocidade de voo do pokï¿½mon.\nHeld Cure - chance de curar condiï¿½ï¿½es do pokï¿½mon a cada segundo.", img = "imgs/sistemasadv/sa8"},
        {name = "09. Reborn System",        text = "O sistema de Reborn, serve para vocï¿½ voltar ao nï¿½vel um e poder refazer algumas quests. Algumas dungeons e sistemas tem um requisito mï¿½nimo de reborns necessï¿½rios.\nPara rebornar basta atingir o nï¿½vel 1000 e digitar /reborn .\nO limite mï¿½ximo de reborns ï¿½ 10.", img = "imgs/sistemasadv/sa9"},
        {name = "10. PokePARK",text = "PokePARK ï¿½ um evento global que acontece toda terï¿½a, quinta, sï¿½bado e domingo, as 11:00, 16:00 e 21:00.\nPara acessar o PokePARK voce deve ter um PokePARK ticket, que pode ser obtido no shop do jogo, por quests ou trade.\n\nAo entrar no PokePARK, voce receberï¿½ 50 parkballs, sï¿½o pokï¿½bolas com o multiplicador de cacch altï¿½ssimos, tornando o catch muito fï¿½cil. Porï¿½m, para ao capturar um pokï¿½mon no pokï¿½park, vocï¿½ nï¿½o fica com ele, e sim, ganha pontos.\nEsses pontos podem ser utilizados para comprar os pokï¿½mons do PokePARK, caso voce os tenha capturado.\nA entrada do PokePARK fica ï¿½ esquerda do centro pokï¿½mon de Port Harbor, utilize !teleport port harbor com algum pokï¿½mon com teleport para ir atï¿½ lï¿½.", img = "imgs/sistemasadv/sa10"},
        {name = "11. Saffari Zone",              text = "A Saffari Zone ï¿½ uma ï¿½rea artificial com diversos pastos com vï¿½rios pokï¿½mons. Quando vocï¿½ entra em um pasto, ninguï¿½m mais pode entrar atï¿½ vocï¿½ sair. O saffari tem uma variedade muito grande de pastos e pokï¿½mons pokï¿½mons exclusivos. Para entrar no Saffari, basta ir a port harbor com o teleport (!teleport port harbor) e ir a direita do centro pokï¿½mon. Para entrar vocï¿½ precisarï¿½ de 100 tokens.", img = "imgs/sistemasadv/sa11"},
        {name = "12. Food System",            text = "As comidas no jogo servem como as potions para pokï¿½mons, porï¿½m para jogadores. Ao consumir uma comida, vocï¿½ ira regenerar vida a cada segundo, de acordo com a comida utilizada.\n\nDiversos NPCs vendem comida pelo mundo, e caso vocï¿½ possua um computador, pode optar por comprar pelo Pokï¿½ Food.", img = "imgs/sistemasadv/sa12"},
        {name = "13. Mega System",             text = "Alguns pokï¿½mons possuem sua Mega Evoluï¿½ï¿½o e podem spawnar evoluidos pelo mapa. Derrotar um desses pokï¿½mons te garante a chance de dropar uma mega stone daquele pokï¿½mon. Ao utilizar a mega stone em um pokï¿½mon seu, ele se tornarï¿½ mega tambï¿½m, ficando ainda mais forte.", img = "imgs/sistemasadv/sa13"},
        {name = "14. Quest Log",         text = "Quest Log ï¿½ uma ferramenta de fï¿½cil acesso que facilita a vida do jogador. Seu intuito ï¿½ mostrar as quests disponï¿½veis para o seu nï¿½vel, sempre atualizando conforme voce upa.\nO Quest log tambï¿½m, mostra as quests que vocï¿½ jï¿½ finalizou, pra poder lembrar quais foram feitas ou nï¿½o.\n\nPara acessar o quest log basta clicar no ï¿½cone no canto superior direito.", img = "imgs/sistemasadv/sa14"},
		{name = "15. Random Encounter",         text = "Random Encounter permite que vocï¿½ encontre pokï¿½mons lendï¿½rios raramente quando derrota pokï¿½mons.\nCaso derrote pokï¿½mons de Johto, vocï¿½ tem a chance de encontrar um dos cï¿½es lendï¿½rios.\nCaso derrote pokï¿½mons de Hoenn, vocï¿½ tem a chance de encontrar Latios ou Latias.\nCaso derrote pokï¿½mons de sinnoh, vocï¿½ tem chance de encontrar Cresselia, caso tenha feito a quest de liberaï¿½ï¿½o.", img = "imgs/sistemasadv/sa15"},
	},	

-- NPCs --
	{
