		{name = "02. Job Manager",      text = "Presente no segundo andar do centro pokï¿½mon de saffron, possibilita o jogador aderir uma profissï¿½o.", img = "imgs/npc/n2"},
		{name = "03. Eva",      text = "Presente no segundo andar do centro pokï¿½mon de saffron, responsï¿½vel pelo sistema de banco.", img = "imgs/npc/n3"},
		{name = "04. Mark",      text = "Presente no trading center, vende itens essenciais para a jornada de um treinador e compra itens dropados dos pokï¿½mons.", img = "imgs/npc/n4"},
