		{name = "10. NPC Duel",      text = "Espalhados pelo mundo inteiro, estes NPCs irï¿½o duelar com vocï¿½ e caso vocï¿½ venï¿½a, irï¿½ receber um prï¿½mio.", img = "imgs/npc/n10"},
