-- Moedas --       
	{
        {name = "01. Gold Coin",      text = "A moeda principal do jogo, possuindo 4 variaï¿½ï¿½es.\n\nGold Coin: Cada gold coin equivale ï¿½ 1 gold coin.\nPlatinum Coin: Cada platinum coin equivale a 100 gold coins.\nCrystal Coin: Cada crystal coin equivale a 100 platinum coins, que equivale a 10.000 gold coins.\nQuartz Coin: Cada quartz coin equivale a 100 crystal coin, que equivale a 1.000.000 gold coins.", img = "imgs/base"},
		{name = "02. Token",      text = "O token ï¿½ uma moeda secundï¿½ria do jogo, que vocï¿½ recebe ao completar quests, tasks, trials e bosses.\nVocï¿½ pode trocar os tokens no NPC Token Collector, no TC.", img = "imgs/base"},
		{name = "03. Park Points",      text = "Moeda utilizada para comprar pokï¿½mons e itens do PokePARK. Adquirida ao completar o evento PokePARK.", img = "imgs/base"},
		{name = "04. Pack de Pï¿½",      text = "Pack de Pï¿½ ou PP ï¿½ a moeda de doaï¿½ï¿½o do servidor, para cada 1 real doado vocï¿½ recebe 1 pack de pï¿½.\nVocï¿½ pode utilizar os packs de pï¿½ para comprar itens em nosso shop.", img = "imgs/base"},
 	},	 
	
-- Doaï¿½ï¿½o --       
	{
        {name = "01. Introduï¿½ï¿½o ï¿½ doaï¿½ï¿½o",      text = "O servidor ï¿½ um fï¿½-game, logo, nï¿½o temos intenï¿½ï¿½es lucrativas. Todas as doaï¿½ï¿½es feitas sï¿½o para ajudar a manter o servidor online.\nCaso vocï¿½ decida doar, serï¿½ muito apreciado, porï¿½m, lembre-se, doe somente se vocï¿½ gostar do jogo e se tiver condiï¿½ï¿½es de fazer isso!", img = "imgs/base"},
		{name = "02. Instruï¿½ï¿½es para doar",      text = "Para doar vocï¿½ deve enviar um pix para: \nowatari.zayon@gmail.com\nApï¿½s isso, encaminhe um print ou informe ao ADM no discord/ingame para que ele cheque a doaï¿½ï¿½o.\nAssim que a doaï¿½ï¿½o for constatada, serï¿½ entregue ao seu depot os packs de pï¿½.", img = "imgs/base"},
 	},	 
}